import{_ as l,o as t,c as r,a2 as o}from"./chunks/framework.DnrXFDHb.js";const u=JSON.parse('{"title":"F05: 應收帳款品質與收款天數 - 財務審計專家報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/6261_久元/20260511/F05_應收帳款品質與收款天數.md","filePath":"審計報告庫/財務審計/6261_久元/20260511/F05_應收帳款品質與收款天數.md"}'),e={name:"審計報告庫/財務審計/6261_久元/20260511/F05_應收帳款品質與收款天數.md"};function i(n,a,s,h,d,_){return t(),r("div",null,[...a[0]||(a[0]=[o('<h1 id="f05-應收帳款品質與收款天數-財務審計專家報告" tabindex="-1">F05: 應收帳款品質與收款天數 - 財務審計專家報告 <a class="header-anchor" href="#f05-應收帳款品質與收款天數-財務審計專家報告" aria-label="Permalink to &quot;F05: 應收帳款品質與收款天數 - 財務審計專家報告&quot;">​</a></h1><p>我已讀取 03_審計專家_任務執行與技術協議.md，我將以專業職人視角，榨取最高密度的財務洞見。</p><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><blockquote><p>應收帳款 (AR) 的規模與週轉天數 (DSO) 變動為何？是否存在客戶拖欠或虛增營收風險？</p></blockquote><h2 id="🎯-專家直斷-66-字" tabindex="-1">🎯 專家直斷（66 字） <a class="header-anchor" href="#🎯-專家直斷-66-字" aria-label="Permalink to &quot;🎯 專家直斷（66 字）&quot;">​</a></h2><ul><li><strong>核心結論</strong>：DSO 由 86 天（2024）跳升至 119 天（2025，+38%），2025 年 AR 增加 2.96 億現金流出，同期營收僅微增 5.6%。AR 增速顯著超越營收，存在放寬授信或塞貨警訊。</li><li><strong>風險評級</strong>：高</li><li><strong>數據時效</strong>：根據截至 2025 年合併財報數據</li></ul><h2 id="📊-診斷評級-139-字" tabindex="-1">📊 診斷評級（139 字） <a class="header-anchor" href="#📊-診斷評級-139-字" aria-label="Permalink to &quot;📊 診斷評級（139 字）&quot;">​</a></h2><ul><li><strong>重點數據</strong>：AR 淨額 9.03 億（2024）→12.35 億（2025，+36.7%）；營收 39.7 億→41.9 億（+5.6%）；DSO 86 天→119 天（+33 天）；現金流量表顯示 AR 增加 2.96 億（2025）vs AR 減少 0.72 億（2024）。逾期率由 34.5% 降至 11.5%，備抵損失由 8,509 萬降至 4,082 萬。</li><li><strong>診斷見解</strong>：DSO 惡化程度嚴重（+38%），但帳齡結構反而改善——逾期佔比顯著下降。矛盾現象解釋：可能因大額新客戶授信期較長（60-90 天）但信用評級佳，導致整體 DSO 上升但逾期率下降。仍需關注 AR 現金回收速度減緩對營運資金的壓力。</li></ul><h2 id="🔍-答詢詳解-420-字" tabindex="-1">🔍 答詢詳解（420 字） <a class="header-anchor" href="#🔍-答詢詳解-420-字" aria-label="Permalink to &quot;🔍 答詢詳解（420 字）&quot;">​</a></h2><h3 id="一、dso-趨勢與營收背離測試" tabindex="-1">一、DSO 趨勢與營收背離測試 <a class="header-anchor" href="#一、dso-趨勢與營收背離測試" aria-label="Permalink to &quot;一、DSO 趨勢與營收背離測試&quot;">​</a></h3><ul><li><strong>核心重點</strong>：DSO 由 2024 年的 86 天（近年最佳）惡化至 2025 年的 119 天（+38%）。AR 成長 36.7%（9.03→12.35 億）遠超營收成長 5.6%（39.7→41.9 億），AR/營收倍比高達 6.6 倍，超過 1.5 倍警戒線 4.4 倍。現金流量表顯示 AR 佔用現金 2.96 億，完全抵銷營業利益現金生成。</li><li><strong>深度見解</strong>：此種背離通常代表兩種情境之一：(1) 公司為衝刺營收，放寬對特定大客戶的授信條件；(2) 年底集中出貨設備（自有產品），設備安裝驗收流程長，導致 AR 暫時積壓。從帳齡改善來看，情境 (2) 可能性較高——設備交易金額大、付款條件寬鬆但信用風險低。</li></ul><h3 id="二、帳齡與壞帳準備審查" tabindex="-1">二、帳齡與壞帳準備審查 <a class="header-anchor" href="#二、帳齡與壞帳準備審查" aria-label="Permalink to &quot;二、帳齡與壞帳準備審查&quot;">​</a></h3><ul><li><strong>核心重點</strong>：2024 年逾期率 34.5%（逾 181 天達 1.96 億），2025 年驟降至 11.5%（逾 181 天 0.98 億）。備抵損失率同步由 8.6%（8,509 萬/9.88 億總額）降至 3.2%（4,082 萬/12.76 億）。</li><li><strong>深度見解</strong>：逾期率改善幅度顯著，2024 年逾 181 天呆帳達 1.96 億（備抵 7,022 萬，覆蓋率 35.8%），2025 年降至 9,773 萬（備抵 3,569 萬，覆蓋率 36.5%）。高齡逾期款項回收約 1 億，反映 2024 年積極催收有成效。但備抵損失率從 8.6% 降至 3.2%，縮減幅度大於帳齡改善幅度——若 2025 年新增 AR 中有部分最終逾期，備抵可能不足。</li></ul><h3 id="三、營運資金循環壓力-附-2026-月營收更新" tabindex="-1">三、營運資金循環壓力（附 2026 月營收更新） <a class="header-anchor" href="#三、營運資金循環壓力-附-2026-月營收更新" aria-label="Permalink to &quot;三、營運資金循環壓力（附 2026 月營收更新）&quot;">​</a></h3><ul><li><strong>核心重點</strong>：AR 增加 2.96 億（2025 年現金流出）加上存貨增加 0.12 億，合計營運資金佔用 3.08 億，對應 CFO 僅 6.64 億，營運資金佔 CFO 的 46.4%。</li><li><strong>深度見解</strong>：營運資金佔用比例偏高。<strong>2026 年 1-4 月月營收（FinMind）累計 13.94 億 YoY +6.3%</strong>，顯見營收已回溫，上半年動能尚可（Q1 +8.9%），但 4 月已降溫至 -1.2%。若下半年續弱，營收增長不足以自然去化 AR 積壓，Q1 DSO 258 天（部分年度效應）方向仍令人擔憂。</li></ul><h2 id="💡-專家評析-281-字" tabindex="-1">💡 專家評析（281 字） <a class="header-anchor" href="#💡-專家評析-281-字" aria-label="Permalink to &quot;💡 專家評析（281 字）&quot;">​</a></h2><ol><li><strong>DSO 急遽惡化（利空）</strong>：119 天遠優於一般製造業 90 天紅線。即使排除設備出貨的結構性因素，119 天仍代表從出貨到收到現金需近 4 個月。若 2026 年設備訂單降溫，應收帳款去化將更困難，營運資金鏈承受實質壓力。</li><li><strong>營收與 AR 嚴重脫鉤（警訊）</strong>：AR 增速（+36.7%）為營收增速（+5.6%）的 6.6 倍，強烈暗示營收品質稀釋。雖帳齡分析未同步惡化，但若管理層以放寬授信為手段維持設備營收規模，一旦客戶違約或展延付款，壞帳損失將直接侵蝕營益率。</li><li><strong>備抵損失率縮減過快（風險）</strong>：備抵率從 8.6% 降至 3.2%，而逾期率從 34.5% 降至 11.5%，備抵降幅（-63%）遠大於逾期率降幅（-67%）。若部分新 AR 最終逾期，3.2% 的備抵率可能不足覆蓋信用損失，存在回沖壓力。</li></ol><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ul><li>計算工具：財務分析工具.py (receivable_check 6261)</li><li>原始數據：2025 Q4 合併財報（第 8 頁資產負債表、第 12 頁現金流量表、第 34-35 頁附註十應收帳款帳齡分析）</li><li>查詢參數：stock_id=6261, 年度 2024-2025</li><li>數據查詢日期：2026-05-11</li></ul>',19)])])}const g=l(e,[["render",i]]);export{u as __pageData,g as default};
